class Solution(object):
    def maxSum(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        MOD = 10**9 + 7

        # The operation transfers bits between numbers
        # Optimal: consolidate all bits into largest k numbers

        # Collect all bits
        bit_counts = [0] * 32
        for num in nums:
            for bit in range(32):
                if num & (1 << bit):
                    bit_counts[bit] += 1

        # Greedily assign bits to maximize largest k numbers
        nums.sort(reverse=True)
        result_nums = [0] * k

        for bit in range(31, -1, -1):
            for i in range(k):
                if bit_counts[bit] > 0:
                    result_nums[i] |= (1 << bit)
                    bit_counts[bit] -= 1

        # Calculate sum of squares
        ans = 0
        for num in result_nums:
            ans = (ans + num * num) % MOD

        return ans
